import * as React from "react";

function YesFifthPageNo() {
    return (
        <>
            <div className="div-61">
                <div className="div-62">
                    Private Pension
                    <br />
                    Withdrawal
                </div>
                <div className="div-63">
                    Have you withdrawn money from any of your private pensions?
                </div>
                <div className="div-64">
                    <div className="div-65">YES</div>
                    <div className="div-66">NO</div>
                </div>
                <div className="div-67">Annual Allowance Calculation </div>
            </div>
        </>
    );
}


export default YesFifthPageNo;
